import{_ as t,o as a,c as r,ae as o}from"./chunks/framework.DTQlDYOH.js";const g=JSON.parse('{"title":"Getting started","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started.md","filePath":"getting-started.md"}'),n={name:"getting-started.md"};function i(s,e,d,l,h,c){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="getting-started" tabindex="-1">Getting started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting started&quot;">​</a></h1><p>This page walks through a minimal B.A.G.E.L. game: a 3×3 grid, one move (place a marker), and two end conditions (win by line or draw when full).</p><h2 id="minimal-game-three-in-a-row" tabindex="-1">Minimal game: three in a row <a class="header-anchor" href="#minimal-game-three-in-a-row" aria-label="Permalink to &quot;Minimal game: three in a row&quot;">​</a></h2><p>See the full example in the repo at <code>server/tic-tac-toe2.json</code>. Summary:</p><ul><li><strong>entities</strong>: one Grid named <code>mainGrid</code>, width 3, height 3</li><li><strong>numPlayers</strong>: 2</li><li><strong>moves.placePlayerMarker</strong>: type <code>PlaceNew</code>, entity thatMatches <code>isCurrentPlayer</code>, destination thatMatches a Space and isEmpty, playerChoice true</li><li><strong>endConditions</strong>: (1) HasLine on mainGrid, sequence of 3 with ContainsSame player → winner ownerOfFirstResultEntity; (2) IsFull on mainGrid → draw</li></ul><h2 id="what-each-part-does" tabindex="-1">What each part does <a class="header-anchor" href="#what-each-part-does" aria-label="Permalink to &quot;What each part does&quot;">​</a></h2><ul><li><strong>entities</strong> — One grid named <code>mainGrid</code>, 3×3. The engine also adds a shared board and per-player “playerMarker” entities.</li><li><strong>numPlayers</strong> — 2 (equivalent to <code>minPlayers</code> and <code>maxPlayers</code> both 2).</li><li><strong>moves.placePlayerMarker</strong> — A <strong>PlaceNew</strong> move: take an entity that matches “current player’s marker” and place it at a <strong>destination</strong> that is a <strong>Space</strong> and <strong>isEmpty</strong>. The player picks the destination (<code>playerChoice: true</code>).</li><li><strong>endConditions</strong> — Two outcomes: <ol><li>If the grid <strong>HasLine</strong> of 3 spaces that <strong>ContainsSame</strong> <code>player</code> → <strong>winner</strong> is the owner of the first such entity (shorthand: <code>ownerOfFirstResultEntity</code>).</li><li>If the grid <strong>IsFull</strong> → <strong>draw</strong>.</li></ol></li></ul><p>Shorthand used here: <code>thatMatches</code> (→ <code>conditions</code>), <code>isCurrentPlayer</code>, <code>isEmpty</code>, <code>endConditions</code> (→ <code>endIf</code>). See <a href="/docs/reference/shorthand.html">Shorthand</a> for the full list.</p><h2 id="try-it-in-the-editor" tabindex="-1">Try it in the editor <a class="header-anchor" href="#try-it-in-the-editor" aria-label="Permalink to &quot;Try it in the editor&quot;">​</a></h2><ol><li>Open the app’s game editor (where you define games).</li><li>Choose the “Three in a Row” example or paste the JSON above into a blank game.</li><li>Run a test game and confirm win/draw behavior.</li></ol><p>From here, explore <a href="./reference/overview.html">Reference</a> for the full structure, <a href="./reference/moves.html">Moves</a> and <a href="./reference/conditions.html">Conditions</a>, or the <a href="./examples/tic-tac-toe.html">Examples</a> for more complex games.</p>',11)])])}const p=t(n,[["render",i]]);export{g as __pageData,p as default};
